import { setup, assign } from 'xstate';

interface FileItem { id: string; name: string; size: number; progress: number }
interface Ctx { files: FileItem[]; hovering: boolean }

type Ev =
  | { type: 'DRAG_ENTER' }
  | { type: 'DRAG_LEAVE' }
  | { type: 'DROP'; files: { id: string; name: string; size: number }[] }
  | { type: 'PROGRESS'; id: string; progress: number }
  | { type: 'DONE'; id: string };

export const dropZoneMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev }
}).createMachine({
  id: 'dropZone',
  context: { files: [], hovering: false },
  initial: 'idle',
  states: {
    idle: {
      on: {
        DRAG_ENTER: { target: 'hover', actions: assign({ hovering: () => true }) }
      }
    },
    hover: {
      on: {
        DRAG_LEAVE: { target: 'idle', actions: assign({ hovering: () => false }) },
        DROP: {
          target: 'queued',
          actions: assign({
            hovering: () => false,
            files: ({ event }) => event.files.map((f) => ({ ...f, progress: 0 }))
          })
        }
      }
    },
    queued: {
      on: {
        PROGRESS: {
          target: 'uploading',
          actions: assign({
            files: ({ context, event }) =>
              context.files.map((f) => (f.id === event.id ? { ...f, progress: event.progress } : f))
          })
        }
      }
    },
    uploading: {
      on: {
        PROGRESS: {
          actions: assign({
            files: ({ context, event }) =>
              context.files.map((f) => (f.id === event.id ? { ...f, progress: event.progress } : f))
          })
        },
        DONE: {
          actions: assign({
            files: ({ context, event }) =>
              context.files.map((f) => (f.id === event.id ? { ...f, progress: 100 } : f))
          })
        }
      }
    }
  }
});
