import { setup, assign } from 'xstate';

const MAX = 5;

interface FileItem { id: string; name: string }
interface Ctx { files: FileItem[] }

type Ev =
  | { type: 'DRAG_OVER' }
  | { type: 'DRAG_OUT' }
  | { type: 'DROP'; items: FileItem[] };

export const boundedDropZoneMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    accept: assign({
      files: ({ context, event }) => {
        if (event.type !== 'DROP') return context.files;
        return [...context.files, ...event.items].slice(0, MAX);
      }
    })
  },
  guards: {
    underLimit: ({ context }) => context.files.length < MAX
  }
}).createMachine({
  id: 'boundedDrop',
  context: { files: [] },
  initial: 'idle',
  states: {
    idle: {
      on: { DRAG_OVER: 'hover' }
    },
    hover: {
      on: {
        DRAG_OUT: 'idle',
        DROP: [
          { guard: 'underLimit', target: 'queued', actions: 'accept' },
          { target: 'rejected' }
        ]
      }
    },
    queued: { on: { DRAG_OVER: 'hover' } },
    rejected: { after: { 2000: 'idle' } }
  }
});
