import { setup, assign, fromPromise, stopChild, type ActorRefFrom } from 'xstate';

const upload = fromPromise<{ id: string }, { id: string }>(async ({ input }) => ({ id: input.id }));

interface FileRef { id: string; ref: ActorRefFrom<typeof upload> }
interface Ctx { files: FileRef[] }

type Ev = { type: 'DROP'; ids: string[] } | { type: 'CANCEL'; id: string };

export const cancellableDropMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { upload }
}).createMachine({
  id: 'cancellableDrop',
  context: { files: [] },
  initial: 'ready',
  states: {
    ready: {
      on: {
        DROP: {
          actions: assign({
            files: ({ event, spawn }) =>
              event.ids.map((id) => ({ id, ref: spawn('upload', { id, input: { id } }) }))
          })
        },
        CANCEL: {
          actions: [
            stopChild(({ context, event }) => {
              const hit = context.files.find((f) => f.id === event.id);
              return hit ? hit.ref : event.id;
            }),
            assign({
              files: ({ context, event }) => context.files.filter((f) => f.id !== event.id)
            })
          ]
        }
      }
    }
  }
});
