```typescript
import { setup, enqueueActions } from 'xstate';

interface Ctx { ids: string[] }

type Ev = { type: 'JOIN'; id: string } | { type: 'WELCOME'; id: string };

type Em = { type: 'PEERS'; n: number };

export const collabMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev, emitted: {} as Em }
}).createMachine({
  id: 'collab',
  context: { ids: [] },
  initial: 'ready',
  states: {
    ready: {
      on: {
        JOIN: {
          actions: enqueueActions(({ enqueue, event }) => {
            enqueue.assign({ ids: ({ context }) => [...context.ids, event.id] });
            enqueue.emit(({ context }) => ({ type: 'PEERS' as const, n: context.ids.length }));
            enqueue.raise({ type: 'WELCOME', id: event.id });
          })
        },
        WELCOME: { actions: () => undefined }
      }
    }
  }
});
