v5 replaces v4's `cancel` action with a typed `cancel(id)` and schedules sends with `sendTo(..., { id, delay })` or `raise(..., { id, delay })`. When the user answers early, the transition lists `cancel('autoSubmit')` as an action so the delayed event is invalidated before it fires.

```typescript
import { setup, assign, raise, cancel } from 'xstate';

interface Ctx { answer: string | null }

type Ev = { type: 'ANSWER'; value: string } | { type: 'AUTO_SUBMIT' } | { type: 'START' };

export const cancellableQuizTimerMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev }
}).createMachine({
  id: 'cancellableQuiz',
  context: { answer: null },
  initial: 'idle',
  states: {
    idle: { on: { START: 'ticking' } },
    ticking: {
      entry: raise({ type: 'AUTO_SUBMIT' }, { id: 'autoSubmit', delay: 15_000 }),
      on: {
        ANSWER: {
          target: 'submitted',
          actions: [cancel('autoSubmit'), assign({ answer: ({ event }) => event.value })]
        },
        AUTO_SUBMIT: 'timedOut'
      }
    },
    submitted: { type: 'final' },
    timedOut: { type: 'final' }
  }
});
```

