      on: {
        ADD: { actions: assign({ items: ({ context, event }) => [...context.items, event.item] }) },
        REMOVE: {
          actions: assign({ items: ({ context, event }) => context.items.filter((i) => i.id !== event.id) })
        },
        SHARE: {
          actions: [
            assign({
              sharedWith: ({ context, event }) =>
                context.sharedWith.includes(event.userId) ? context.sharedWith : [...context.sharedWith, event.userId]
            }),
            emit(({ context, event }) => ({
              type: 'SHARED' as const,
              userId: event.userId,
              count: context.items.length
            }))
          ]
        }
      }
    }
