      invoke: {
        src: 'buildActor',
        input: ({ context }) => ({ version: context.version }),
        onDone: { target: 'done', actions: assign({ sha: ({ event }) => event.output.sha }) },
        onError: [
          { guard: 'canRetry', target: 'building', reenter: true },
          { target: 'failed' }
        ]
      }
    },
    done: { type: 'final' },
    failed: { on: { RETRY: 'building' } }
  }
